#!/bin/bash
# Simplified project scanner

PROJECT_ROOT="$1"
OUTPUT_FILE="$2"

cd "$PROJECT_ROOT" || exit 1

# Get all tracked files
FILES=$(git ls-files 2>/dev/null || find . -type f -not -path '*/\.*' -not -path '*/node_modules/*' -not -path '*/build/*' -not -path '*/output/*')

# Language detection function
detect_language() {
    local file="$1"
    local ext="${file##*.}"
    local basename="${file##*/}"

    case "$basename" in
        Dockerfile|Dockerfile.*) echo "dockerfile" ;;
        Makefile) echo "makefile" ;;
        Jenkinsfile) echo "jenkinsfile" ;;
        CMakeLists.txt) echo "cmake" ;;
        *)
            case "$ext" in
                cpp|cc|cxx) echo "c++" ;;
                c) echo "c" ;;
                h|hpp|hxx) echo "c++" ;;
                py) echo "python" ;;
                js) echo "javascript" ;;
                ts) echo "typescript" ;;
                java) echo "java" ;;
                go) echo "go" ;;
                rs) echo "rust" ;;
                sh|bash) echo "shell" ;;
                yaml|yml) echo "yaml" ;;
                json) echo "json" ;;
                md|mdx) echo "markdown" ;;
                txt) echo "text" ;;
                xml) echo "xml" ;;
                toml) echo "toml" ;;
                ini) echo "ini" ;;
                gitignore|gitmodules) echo "gitconfig" ;;
                *) echo "unknown" ;;
            esac
            ;;
    esac
}

# Category detection function
detect_category() {
    local file="$1"
    local basename="${file##*/}"
    local ext="${file##*.}"

    # Priority checks
    case "$basename" in
        LICENSE|NOTICE) echo "code"; return ;;
        Dockerfile*|docker-compose.*|Makefile|Jenkinsfile|Procfile) echo "infra"; return ;;
        .dockerignore|.gitlab-ci.yml) echo "infra"; return ;;
    esac

    case "$file" in
        .github/workflows/*|.circleci/*|k8s/*|kubernetes/*) echo "infra"; return ;;
    esac

    case "$ext" in
        md|mdx|rst|txt)
            [[ "$basename" != "LICENSE" ]] && echo "docs" || echo "code"
            return ;;
        yaml|yml|json|jsonc|toml|xml|ini|cfg|properties|env) echo "config"; return ;;
        sh|bash|zsh|ps1|bat|cmd) echo "script"; return ;;
        html|htm|css|scss|sass|less) echo "markup"; return ;;
        sql|graphql|gql|proto|csv|tsv) echo "data"; return ;;
        tf|tfvars) echo "infra"; return ;;
        *) echo "code"; return ;;
    esac
}

# Count lines
count_lines() {
    wc -l < "$1" 2>/dev/null || echo "0"
}

# Build JSON
echo '{"scriptCompleted":true,"files":[' > "$OUTPUT_FILE"

first=true
total=0
declare -A lang_count
declare -A cat_count

while IFS= read -r file; do
    [[ -f "$file" ]] || continue

    lang=$(detect_language "$file")
    cat=$(detect_category "$file")
    lines=$(count_lines "$file")

    ((total++))
    ((lang_count[$lang]++))
    ((cat_count[$cat]++))

    if [ "$first" = true ]; then
        first=false
    else
        echo "," >> "$OUTPUT_FILE"
    fi

    printf '{"path":"%s","language":"%s","sizeLines":%d,"fileCategory":"%s"}' \
        "$file" "$lang" "$lines" "$cat" >> "$OUTPUT_FILE"
done <<< "$FILES"

# Calculate complexity
if [ $total -lt 50 ]; then
    complexity="simple"
elif [ $total -lt 200 ]; then
    complexity="moderate"
else
    complexity="complex"
fi

# Build stats
echo -n '],"totalFiles":'$total',"filteredByIgnore":0,"estimatedComplexity":"'$complexity'","stats":{"filesScanned":'$total',"byCategory":{' >> "$OUTPUT_FILE"

first=true
for cat in "${!cat_count[@]}"; do
    if [ "$first" = true ]; then
        first=false
    else
        echo -n "," >> "$OUTPUT_FILE"
    fi
    echo -n '"'$cat'":'${cat_count[$cat]} >> "$OUTPUT_FILE"
done

echo -n '},"byLanguage":{' >> "$OUTPUT_FILE"

first=true
for lang in "${!lang_count[@]}"; do
    if [ "$first" = true ]; then
        first=false
    else
        echo -n "," >> "$OUTPUT_FILE"
    fi
    echo -n '"'$lang'":'${lang_count[$lang]} >> "$OUTPUT_FILE"
done

echo '}}}' >> "$OUTPUT_FILE"

echo "scan-project: filesScanned=$total filteredByIgnore=0 complexity=$complexity" >&2
